const items = $input.all();

const results = [];

for (const item of items) {
  const app = item.json;
  const experience = app['Experience (Years)'];
  const skills = app['Skills'].split(',').map(s => s.trim());

  // Score based on experience
  let experienceScore = 0;
  if (experience >= 5) experienceScore = 40;
  else if (experience >= 3) experienceScore = 30;
  else if (experience >= 1) experienceScore = 20;
  else experienceScore = 10;

  // Score based on skills
  const keySkills = ['n8n', 'JavaScript', 'Python', 'APIs', 'AI', 'Zapier'];
  const matchedSkills = skills.filter(s => keySkills.includes(s));
  const skillScore = Math.min(matchedSkills.length * 15, 60);

  const totalScore = experienceScore + skillScore;

  let recommendation;
  if (totalScore >= 80) recommendation = 'Strong Hire';
  else if (totalScore >= 60) recommendation = 'Hire';
  else if (totalScore >= 40) recommendation = 'Maybe';
  else recommendation = 'Reject';

  results.push({
    json: {
      applicationId: app['Application ID'],
      candidateName: app['Candidate Name'].trim(),
      email: app['Email'],
      position: app['Position'],
      experience,
      skills: app['Skills'],
      matchedSkills: matchedSkills.join(', '),
      totalScore,
      recommendation,
      rowNumber: app['row_number'],
    }
  });
}

return results;

const aiItems = $input.all();
const originalItems = $('Code in JavaScript').all();

return aiItems.map((item, i) => {
  const text = item.json.output?.[0]?.content?.[0]?.text || "";
  const original = originalItems[i]?.json || {};

  const candidateSubjectMatch = text.match(/\*?\*?CandidateSubject:\*?\*?\s*(.+)/);
  const candidateEmailMatch = text.match(/\*?\*?CandidateEmail:\*?\*?\s*([\s\S]+?)(?=\*?\*?ManagerSubject:)/);
  const managerSubjectMatch = text.match(/\*?\*?ManagerSubject:\*?\*?\s*(.+)/);
  const managerEmailMatch = text.match(/\*?\*?ManagerEmail:\*?\*?\s*([\s\S]+)/);

  return {
    json: {
      applicationId: original.applicationId,
      candidateName: original.candidateName,
      candidateEmail: original.email,
      position: original.position,
      totalScore: original.totalScore,
      recommendation: original.recommendation,
      rowNumber: original.rowNumber,
      candidateSubject: candidateSubjectMatch ? candidateSubjectMatch[1].trim() : "",
      candidateEmailBody: candidateEmailMatch ? candidateEmailMatch[1].trim() : "",
      managerSubject: managerSubjectMatch ? managerSubjectMatch[1].trim() : "",
      managerEmailBody: managerEmailMatch ? managerEmailMatch[1].trim() : "",
    }
  };
});

